export const analyzeProductsFromPhoto = async (
    base64Image: string
): Promise<string[] | null> => {

    const imagePart = {
        inlineData: {
            mimeType: 'image/jpeg',
            data: base64Image.split(',')[1],
        },
    };

    const textPart = {
        text: `あなたは、化粧品の特定を専門とする画像認識AIです。
提供された画像から、写っているすべての化粧品を識別してください。
各製品について、ブランド名と製品名を組み合わせた「正式名称」を特定してください。
特定したすべての製品名を、'products'というキーを持つJSONオブジェクト内の配列として返してください。

例:
{
  "products": ["資生堂 アルティミューン パワライジング コンセントレイト III", "SK-II フェイシャル トリートメント エッセンス"]
}

画像に化粧品が写っていない、または特定できない場合は、空の配列を返してください。`
    };

    // Use flash for vision tasks
    const response = await callGeminiWithRetry(
        () => ai.models.generateContent({
            model: "gemini-2.5-flash",
            contents: { parts: [imagePart, textPart] },
            config: {
                responseMimeType: "application/json",
                responseSchema: productAnalysisSchema,
            },
        }),
        "AIによる製品の分析に失敗しました。",
        "AIサーバーが混み合っています。しばらくしてからもう一度お試しください。"
    );

    const result = JSON.parse(response.text);
    if (result && Array.isArray(result.products)) {
        return result.products;
    }
    return null;
};

const photoValidationSchema = {
    type: Type.OBJECT,
    properties: {
        isValid: { 
            type: Type.BOOLEAN, 
            description: "ビデオフレームが肌分析に適しているかどうかの判定結果。"
