// This functions handles VIDEO data (base64) directly
export const validateVideoForSkinAnalysis = async (
    videoDataUrl: string
): Promise<PhotoValidationResult> => {

    console.log("[Gemini Service] Starting video validation. Data URL length:", videoDataUrl.length);

    // Extract mimeType and base64 data
    const matches = videoDataUrl.match(/^data:(.+);base64,(.+)$/);
    if (!matches) {
        console.error("[Gemini Service] Invalid video data format in validation");
        throw new Error("Invalid video data format");
    }
    let mimeType = matches[1];
    const base64Data = matches[2];

    console.log(`[Gemini Service] Original MIME Type: ${mimeType}`);
    console.log(`[Gemini Service] Base64 Payload Length: ${base64Data.length}`);

    if (base64Data.length === 0) {
        throw new Error("Video data is empty.");
    }

    // Clean mime type for Gemini API compatibility (remove codecs)
    // Gemini accepts video/webm, video/mp4 etc., but may reject parameter strings
    if (mimeType.includes('webm') || mimeType.includes('x-matroska')) {
        mimeType = 'video/webm';
    } else if (mimeType.includes('mp4')) {
        mimeType = 'video/mp4';
    } else if (mimeType.includes(';')) {
        mimeType = mimeType.split(';')[0];
    }

    console.log(`[Gemini Service] Cleaned MIME Type for Gemini: ${mimeType}`);

    const videoPart = {
        inlineData: {
            mimeType: mimeType,
            data: base64Data,
        },
    };

    const textPart = {
        text: `あなたはAI品質管理スペシャリストです。提供されたビデオは、ユーザーが顔を左右に振っている自撮り動画です。このビデオがAI肌診断に適しているかを検証してください。

以下の基準で厳格に評価します:
1.  **明瞭さ:** ピンボケしておらず、鮮明か？
2.  **光量:** 暗すぎたり、明るすぎたり（白飛び）していないか？
3.  **被写体:** 人間の顔がはっきりと、主要な被写体として写っているか？
4.  **障害物:** 顔が手や髪で隠れていたり、肌の状態を隠すほどの厚化粧がされていないか？
5.  **モーションブラー:** 顔を動かしているため多少のブレは許容するが、肌の状態が判別できないほどの過度なモーションブラーはないか？
6.  **アングルの多様性:** 顔の正面だけでなく、側面なども捉えられているか？

分析に基づき、指定されたJSON形式で結果を返してください。

- \`isValid\` (boolean): 全ての基準を総合的に満たせば \`true\`、一つでも重大な問題があれば \`false\`。
- \`reason\` (string): \`isValid\` が \`false\` の場合、ユーザーに再撮影を促すための、簡潔で具体的な理由と解決策を日本語で記述してください。\`isValid\` が \`true\` の場合は、空文字列にしてください。

理由の例:
- "動きが速すぎて、全体的にブレが生じています。もっとゆっくり顔を動かして再撮影してください。"
- "全体的に暗すぎます。より明るい場所で撮影してください。"
- "顔が画面から切れてしまっています。顔全体が写るように撮影してください。"

JSONオブジェクトのみを返してください。`
    };

    // Use flash for vision tasks
    const response = await callGeminiWithRetry(
        () => ai.models.generateContent({
            model: "gemini-2.5-flash",
            contents: { parts: [videoPart, textPart] },
            config: {
                responseMimeType: "application/json",
                responseSchema: photoValidationSchema,
            },
        }),
        "AIによるビデオの品質検証に失敗しました。",
        "AIサーバーが混み合っています。しばらくしてからもう一度お試しください。"
    );
    return JSON.parse(response.text) as PhotoValidationResult;
};

