const buildUserProfileString = (input: ConsultationInput): string => {
    const userInfoParts: string[] = [
        `- **アプローチタイプ:** ${input.type}`,
        `- **年代:** ${input.ageGroup}`,
        `- **肌質:** ${input.skinType}`,
        `- **化粧品知識レベル:** ${input.knowledgeLevel}/5 (1:おまかせ, 5:専門的)`,
        `- **肌トラブルの経験:** ${input.troubleHistory || '特になし'}`
    ];

    if (input.type === 'concerns') {
        const concernsString = Object.entries(input.skinConcerns)
            .map(([concern, severity]) => `${concern} (深刻度: ${severity}/5)`)
            .join(', ');
        userInfoParts.push(`- **主な肌悩み:** ${concernsString}`);
        if (input.lifestyleFactors.length > 0) {
            userInfoParts.push(`- **気になる生活習慣:** ${input.lifestyleFactors.join(', ')}`);
        }
        if (input.concernTimings.length > 0) {
             userInfoParts.push(`- **悩みが気になるタイミング:** ${input.concernTimings.join(', ')}`);
        }
    } else if (input.type === 'ideal') {
        userInfoParts.push(`- **なりたい肌の目標:** ${input.idealSkin}`);
        if (Object.keys(input.skinConcerns).length > 0) {
             const concernsString = Object.entries(input.skinConcerns)
                .map(([concern, severity]) => `${concern} (深刻度: ${severity}/5)`)
                .join(', ');
            userInfoParts.push(`- **現在の主な肌悩み:** ${concernsString}`);
        }
        if (input.lifestyleFactors.length > 0) {
            userInfoParts.push(`- **気になる生活習慣:** ${input.lifestyleFactors.join(', ')}`);
        }
        if (input.currentLacks.length > 0) {
             userInfoParts.push(`- **現在足りないと感じる要素:** ${input.currentLacks.join(', ')}`);
        }
    } else if (input.type === 'investigate') {
        userInfoParts.push(`- **現在使用中の製品名:** ${input.currentUserProducts.join('、')}`);
        if (input.productUsageDuration) {
            userInfoParts.push(`- **使用期間:** ${input.productUsageDuration}`);
        }
        if (input.dissatisfactions.length > 0) {
            userInfoParts.push(`- **現在の製品への不満点:** ${input.dissatisfactions.join(', ')}`);
        }
        userInfoParts.push(`- **なりたい肌の目標:** ${input.idealSkin}`);
    }

    return userInfoParts.join('\n');
};

export const runFullConsultation = async (
    input: ConsultationInput
): Promise<FullConsultationResponse> => {

    let firstConcern = '肌の悩み';
    if ((input.type === 'concerns' || input.type === 'ideal') && input.skinConcerns && Object.keys(input.skinConcerns).length > 0) {
        firstConcern = Object.keys(input.skinConcerns)[0];
    } else if (input.type === 'investigate' && input.dissatisfactions && input.dissatisfactions.length > 0) {
        firstConcern = input.dissatisfactions[0];
    } else if ((input.type === 'ideal' || input.type === 'investigate') && input.idealSkin) {
        firstConcern = `${input.idealSkin}の実現`;
    }

    const userProfileString = buildUserProfileString(input);

    const benchmarkDataString = BENCHMARK_COMPETITORS.map(p => 
        `- ${p.name} (${p.priceTier}): ${SCORE_CATEGORY_KEYS.map(key => `${String(key)} ${p.scores[key]}`).join(', ')}`
    ).join('\n');

    const prompt = `
あなたは、高級スキンケアブランド「EVOLURE」のAI診断エンジンです。
あなたのタスクは、**単一の応答で**以下のステップを順番に実行し、完全な診断結果を生成することです。

**【最重要：薬機法・景品表示法コンプライアンス遵守ガイドライン】**
あなたは日本の化粧品法規制を完全に理解している専門家として振る舞ってください。以下の表現ルールを**絶対に**守ってください。違反した場合、ブランドの信頼に関わります。

1.  **「治る」「消える」の禁止:** 化粧品は病気の治療薬ではありません。「シミが消える」「シワが治る」「ニキビが治癒する」といった表現は禁止です。「シミを防ぐ（※メラニンの生成を抑え、シミ・そばかすを防ぐ）」「乾燥による小ジワを目立たなくする」「ニキビを防ぐ」と言い換えてください。
2.  **「若返り」「再生」の禁止:** 「肌が若返る」「細胞が再生する」「アンチエイジング」という単語は禁止です。「ハリを与える」「キメを整える」「エイジングケア（※年齢に応じたうるおいケア）」と言い換えてください。
3.  **浸透範囲の限定:** 「真皮まで届く」「肌の奥深くまで浸透」は禁止です。浸透表現は必ず「角層まで」の範囲に留めてください。
4.  **安全性の保証禁止:** 「副作用がない」「絶対に安全」「アレルギーが起きない」は禁止です。「低刺激設計」「パッチテスト済み（※全ての方に皮膚刺激が起きないわけではありません）」等の事実に基づく表現にしてください。
5.  **最大級表現の禁止:** 「最高」「最強」「No.1」「劇的」といった客観的根拠のない最大級表現は避けてください。

**ステップ1：ユーザープロファイルの分析**
まず、提供されたユーザープロファイルを深く理解します。
**【重要】ユーザーの定性的な情報（トラブル経験、悩みのタイミングなど）を重視してください。**
- トラブル経験がある場合は、より慎重な導入方法（パッチテストの推奨など）を提案してください。

**ステップ2：製品選択**
次に、ユーザープロファイルとEVOLURE製品カタログに基づき、最適な製品の組み合わせを選択します。
- **美容液選択の基本方針:** ユーザーの「肌悩みの深刻度と数」および「ニーズの方向性」に基づいて、3種類の美容液から最適な1つを選択します。
  - **Serum A (The Masterpiece):** 
    - ターゲット: **深刻なエイジングサイン（シワ、ハリ不足）に悩む層、または「最高峰」を求める層。**
    - 選択基準: 肌悩みの深刻度が「4-5」の項目が複数ある場合、または年齢肌特有の悩み（深いシワ、たるみ）が顕著な場合。予算よりも効果を最優先する場合。
  - **Serum B (The Standard):** 
    - ターゲット: **エイジングケアと予防の両立を求める層、バランス重視の層。**
    - 選択基準: 肌悩みが中程度（2-3）で広範囲にわたる場合、または特定の悩みに特化せず全体的な肌レベルを上げたい場合。Serum Aほどの高価格帯には手が出ないが、高機能なケアを求める場合。
  - **Serum C (The Foundation):** 
    - ターゲット: **予防ケア重視、敏感肌、若年層、またはコストパフォーマンス最優先の層。**
    - 選択基準: 肌悩みが軽度（1-2）である場合、または「乾燥」「肌荒れ予防」が主訴の場合。初めて高機能スキンケアを使う「ゲートウェイ」として提案する場合。

- **アンプル選択の戦略 (Foundation vs Performance):**
  美容液が決まったら、その効果を最大化するためにアンプルを組み合わせます。**積極的な提案**を行ってください。
  - **Foundation Ampoule (バリアケア, ブライトニング):** 肌の基礎を支えるため、基本的に1つ選択します（定期コースの無料枠を活用）。
  - **Performance Ampoule (ハリ・弾力, エイジングケア):** 高度な悩み（深いシワ、たるみ、深刻なエイジングサイン）を持つユーザー、またはより早い結果を求めるユーザーには、**有料であっても躊躇せず積極的に提案に含めてください**。「美容液 + Foundation + Performance」のトリプルケアこそが、EVOLUREの真価を発揮する黄金比です。特に30代後半以降や、深刻度3以上の悩みがある場合は必須級として扱ってください。

**ステップ3：診断カルテの生成**
ステップ2で選択した製品に基づき、プロフェッショナルな「診断カルテ」データを生成します。以下のガイドラインに厳密に従ってください。
