            const report = parsedData.medicalChartReport;
            if (
                !report || typeof report !== 'object' || !Array.isArray(report.summaryBullets) ||
                typeof report.knowledgeLevelRationale !== 'string' || typeof report.patientSummary !== 'string' ||
                typeof report.prescriptionIntent !== 'string' || typeof report.serumRationale !== 'string' ||
                !Array.isArray(report.ampouleRationales) || typeof report.futureOutlook !== 'string' ||
                typeof report.usageInstructions !== 'string' || !Array.isArray(report.serumIngredientAnalysis) ||
                !Array.isArray(report.ampouleIngredientAnalysis)
            ) {
