                throw new Error("AIが生成した診断カルテの情報が不完全です。必須項目が欠落しています。");
            }
        } else {
            parsedData = JSON.parse(response.text);
        }

        const citations = response.candidates?.[0]?.groundingMetadata?.groundingChunks
            ?.map(chunk => ({
                uri: chunk.web?.uri || '',
                title: chunk.web?.title || '引用元情報'
            }))
            .filter(c => c.uri) ?? [];

        const result: FullConsultationResponse = {
            ...parsedData,
            citations: citations,
        };

        if (result.competitorAnalysis) {
            const analysisArray = Array.isArray(result.competitorAnalysis)
                ? result.competitorAnalysis
                : [result.competitorAnalysis];

            result.competitorAnalysis = (analysisArray as any[]).map(p => {
                const validatedScores: Partial<Score> = {};
                SCORE_CATEGORY_KEYS.forEach(key => {
                    const score = p?.scores?.[key];
                    if (typeof score === 'number' && score >= 50 && score <= 100) {
                        validatedScores[key] = score;
                    } else {
                        validatedScores[key] = 60; // default score
                    }
                });

                return {
                    name: `現在: ${p.productName || p.name}`,
                    scores: validatedScores as Score,
                    report: p.report || 'レポートがありません。',
                    citations: result.citations
                };
            });
        }

        return result;

    } catch (error) {
        console.error("Failed to get full consultation from Gemini:", error);
        throw error;
    }
};

