const buildUserProfileString = (input: ConsultationInput): string => {
    const userInfoParts: string[] = [
        `- **アプローチタイプ:** ${input.type}`,
        `- **年代:** ${input.ageGroup}`,
        `- **肌質:** ${input.skinType}`,
        `- **化粧品知識レベル:** ${input.knowledgeLevel}/5 (1:おまかせ, 5:専門的)`,
        `- **肌トラブルの経験:** ${input.troubleHistory || '特になし'}`
    ];

    if (input.type === 'concerns') {
        const concernsString = Object.entries(input.skinConcerns)
            .map(([concern, severity]) => `${concern} (深刻度: ${severity}/5)`)
            .join(', ');
        userInfoParts.push(`- **主な肌悩み:** ${concernsString}`);
        if (input.lifestyleFactors.length > 0) {
            userInfoParts.push(`- **気になる生活習慣:** ${input.lifestyleFactors.join(', ')}`);
        }
        if (input.concernTimings.length > 0) {
             userInfoParts.push(`- **悩みが気になるタイミング:** ${input.concernTimings.join(', ')}`);
        }
    } else if (input.type === 'ideal') {
        userInfoParts.push(`- **なりたい肌の目標:** ${input.idealSkin}`);
        if (Object.keys(input.skinConcerns).length > 0) {
             const concernsString = Object.entries(input.skinConcerns)
                .map(([concern, severity]) => `${concern} (深刻度: ${severity}/5)`)
                .join(', ');
            userInfoParts.push(`- **現在の主な肌悩み:** ${concernsString}`);
        }
        if (input.lifestyleFactors.length > 0) {
            userInfoParts.push(`- **気になる生活習慣:** ${input.lifestyleFactors.join(', ')}`);
        }
        if (input.currentLacks.length > 0) {
             userInfoParts.push(`- **現在足りないと感じる要素:** ${input.currentLacks.join(', ')}`);
        }
    } else if (input.type === 'investigate') {
        userInfoParts.push(`- **現在使用中の製品名:** ${input.currentUserProducts.join('、')}`);
        if (input.productUsageDuration) {
            userInfoParts.push(`- **使用期間:** ${input.productUsageDuration}`);
        }
        if (input.dissatisfactions.length > 0) {
            userInfoParts.push(`- **現在の製品への不満点:** ${input.dissatisfactions.join(', ')}`);
        }
        userInfoParts.push(`- **なりたい肌の目標:** ${input.idealSkin}`);
    }

    return userInfoParts.join('\n');
};

