  const { products, logEvent, updateSession, currentSessionId } = useAdmin();
  const [secretCounter, setSecretCounter] = useState(0);
  const [activeChart, setActiveChart] = useState<'radar' | 'bar'>('radar');

  // Load chat session
  useEffect(() => {
    chatSessionRef.current = createChatSession();
  }, []);

  // Update session data to Admin Context whenever relevant state changes
  useEffect(() => {
      // This is crucial: Captures every state update even if user drops off.
      updateSession(currentSessionId, {
          demographics: {
              ageGroup: state.ageGroup,
              skinType: state.skinType,
              skinConcerns: Object.keys(state.skinConcerns),
              knowledgeLevel: state.knowledgeLevel
          },
          selectedGoal: state.selectedIdealGoal,
          currentProducts: state.currentUserProducts,
          chatHistory: state.chatHistory,
          currentStep: state.currentView === 'consultation' ? 'consultation-form' : state.currentView
      });
  }, [state.ageGroup, state.skinType, state.skinConcerns, state.knowledgeLevel, state.selectedIdealGoal, state.currentUserProducts, state.chatHistory, state.currentView, updateSession, currentSessionId]);

  // FIX: カート投入用のデータを生成するヘルパー関数
  const createCartFromCurrentState = useCallback(() => {
    const newCart: CartItem[] = [];
    if (!state.selectedSerum) return newCart;

    // 1. 美容液の価格決定
    const serumPrice = state.purchaseType === 'subscription' 
        ? (state.selectedSerum.subscriptionPrice || state.selectedSerum.price)
        : state.selectedSerum.price;

    newCart.push({ 
        product: state.selectedSerum, 
        quantity: 1, 
        priceAtPurchase: serumPrice 
    });

    // 2. アンプルの価格決定（定期購入の場合のみ追加）
    if (state.purchaseType === 'subscription') {
        // 無料枠の判定ロジック: パフォーマンスアンプルがない場合に限り、Foundationの1つ目が無料
        const isFreeFoundationEligible = state.selectedPerformanceAmpoules.length === 0;

        // Foundation Ampoules (1つ目が無料の場合がある)
        const sortedFoundation = [...state.selectedFoundationAmpoules].sort((a, b) => a.id.localeCompare(b.id));
        sortedFoundation.forEach((amp, index) => {
            const price = (isFreeFoundationEligible && index === 0) ? 0 : amp.price;
            newCart.push({ 
                product: amp, 
                quantity: 1, 
                priceAtPurchase: price 
            });
        });

        // Performance Ampoules (常に有料)
        state.selectedPerformanceAmpoules.forEach(amp => {
            newCart.push({ 
                product: amp, 
                quantity: 1, 
                priceAtPurchase: amp.price 
            });
        });
    }

    return newCart;
  }, [state.selectedSerum, state.selectedFoundationAmpoules, state.selectedPerformanceAmpoules, state.purchaseType]);

  const calculateTotal = useMemo(() => {
    const cart = createCartFromCurrentState();
    return cart.reduce((sum, item) => {
        const price = item.priceAtPurchase ?? item.product.price;
        return sum + (price * item.quantity);
    }, 0);
  }, [createCartFromCurrentState]);

  const handleStartConsultation = (type: 'concerns' | 'ideal' | 'investigate') => {
    logEvent(currentSessionId, 'VIEW_STEP', { step: 'consultation_start', type });
    dispatch({ type: 'SET_CONSULTATION_TYPE', payload: type });
    dispatch({ type: 'SET_VIEW', payload: 'consultation' });
  };

  // --- Secret Admin Access ---
  const handleLogoClick = () => {
      setSecretCounter(prev => {
          if (prev + 1 >= 5) {
              dispatch({ type: 'SET_VIEW', payload: 'admin' });
              return 0;
          }
          return prev + 1;
      });
  };

  // --- Chart Data Preparation ---
  const radarChartData = useMemo(() => {
    if (!state.selectedSerum || !state.fullPlanScores) return [];

    const data = [];

    // 1. Base Serum
    data.push({
        name: '美容液のみ',
        scores: state.selectedSerum.baseScores
    });

    // 2. Full Plan (only if ampoules are selected)
    const hasAmpoules = (state.selectedFoundationAmpoules.length > 0 || state.selectedPerformanceAmpoules.length > 0) && state.purchaseType === 'subscription';
    if (hasAmpoules) {
        data.push({
            name: 'アンプル追加後',
            scores: state.fullPlanScores
        });
    } else {
        // Change name if no ampoules
        data[0].name = 'あなたのEVOLUREプラン';
    }

    // 3. Competitors (if any)
    if (state.analyzedUserProducts) {
        state.analyzedUserProducts.forEach(comp => {
            data.push({
                name: comp.name,
                scores: comp.scores
            });
        });
    }

    return data;
  }, [state.selectedSerum, state.fullPlanScores, state.selectedFoundationAmpoules, state.selectedPerformanceAmpoules, state.analyzedUserProducts, state.purchaseType]);

  const barChartData = useMemo(() => {
      if (!state.selectedSerum || !state.fullPlanScores) return [];

      const hasAmpoules = (state.selectedFoundationAmpoules.length > 0 || state.selectedPerformanceAmpoules.length > 0) && state.purchaseType === 'subscription';

      return SCORE_CATEGORY_KEYS.map(category => {
          const item: any = { subject: category };

          // Base
          const baseScore = state.selectedSerum!.baseScores[category] || 0;
          item['美容液'] = baseScore;

          // Boost
          if (hasAmpoules) {
              const fullScore = state.fullPlanScores![category] || 0;
              item['アンプル追加分'] = Math.max(0, fullScore - baseScore);
          } else {
               item['あなたのEVOLUREプラン'] = baseScore;
          }

          // Competitors
          if (state.analyzedUserProducts) {
              state.analyzedUserProducts.forEach(comp => {
                  item[comp.name] = comp.scores[category] || 0;
              });
          }
          return item;
      });
  }, [state.selectedSerum, state.fullPlanScores, state.selectedFoundationAmpoules, state.selectedPerformanceAmpoules, state.analyzedUserProducts, state.purchaseType]);


  // --- Chat Handlers ---

  const handleSendChatMessage = async () => {
    if (!state.chatInput.trim()) return;

    const userMessage = state.chatInput;

    // Secret backdoor for admin
    if (userMessage === '/admin') {
        dispatch({ type: 'SET_CHAT_INPUT', payload: '' });
        dispatch({ type: 'SET_VIEW', payload: 'admin' });
        return;
    }

    dispatch({ type: 'SET_CHAT_INPUT', payload: '' });
    dispatch({ type: 'ADD_CHAT_MESSAGE', payload: { role: 'user', content: userMessage, timestamp: Date.now() } });
    dispatch({ type: 'SET_CHAT_LOADING', payload: true });

    logEvent(currentSessionId, 'CHAT_MESSAGE_SENT', { content: userMessage });

    try {
        const stream = await sendChatMessageStream(chatSessionRef.current, userMessage);
        let fullResponse = '';

        // Add placeholder message
        dispatch({ type: 'ADD_CHAT_MESSAGE', payload: { role: 'model', content: '', timestamp: Date.now() } });

        for await (const chunk of stream) {
            const chunkText = chunk.text;
            fullResponse += chunkText;
            dispatch({ type: 'REMOVE_FROM_CART', payload: -1 }); // Dummy action to force re-render
        }

         dispatch({ type: 'ADD_CHAT_MESSAGE', payload: { role: 'model', content: fullResponse, timestamp: Date.now() } });
         logEvent(currentSessionId, 'CHAT_MESSAGE_RECEIVED', { content: fullResponse });

        // Check for JSON commands (Simple parsing)
        const jsonMatch = fullResponse.match(/```json\s*([\s\S]*?)\s*```/);
        if (jsonMatch && jsonMatch[1]) {
            try {
                const command = JSON.parse(jsonMatch[1]);
                handleChatCommand(command);
            } catch (e) {
                console.error("Failed to parse chat command", e);
            }
        }

    } catch (error) {
        console.error(error);
        toast.error('メッセージの送信に失敗しました');
    } finally {
        dispatch({ type: 'SET_CHAT_LOADING', payload: false });
    }
  };

  const handleChatCommand = (command: any) => {
      console.log("Chat Command Received:", command);
      if (command.action === 'start_consultation') {
          // Map payload to state
          const p = command.payload;
          if (p.type) dispatch({ type: 'SET_CONSULTATION_TYPE', payload: p.type });
          if (p.ageGroup) dispatch({ type: 'SET_AGE_GROUP', payload: p.ageGroup });
          if (p.skinConcerns) {
              Object.entries(p.skinConcerns).forEach(([k, v]) => {
                  dispatch({ type: 'SET_SKIN_CONCERN', payload: { concern: k, severity: Number(v) } });
              });
          }
           if (p.knowledgeLevel) dispatch({ type: 'SET_KNOWLEDGE_LEVEL', payload: p.knowledgeLevel });

           // Auto-start
           const input: ConsultationInput = {
               type: p.type,
               ageGroup: p.ageGroup || '30代前半',
               skinType: '混合肌', // Default
               skinConcerns: p.skinConcerns || {},
               lifestyleFactors: [],
               knowledgeLevel: p.knowledgeLevel || 1,
               troubleHistory: '特になし',
               concernTimings: []
           } as any;

           dispatch({ type: 'SET_CONSULTATION_INPUT', payload: input });
           runFullConsultationFlow(input);
      }
  };

  const runFullConsultationFlow = async (input: ConsultationInput) => {
      dispatch({ type: 'SET_VIEW', payload: 'dashboard' });
      dispatch({ type: 'SET_MEDICAL_CHART_LOADING', payload: true });
      logEvent(currentSessionId, 'GENERATE_PLAN', { input });

      try {
        const response = await runFullConsultation(input);

        // Map response IDs to Products
        let selectedSerum: Serum | null = null;
        let selectedFAmps: Ampoule[] = [];
        let selectedPAmps: Ampoule[] = [];

        if (response && response.recommendations && response.recommendations.serumId) {
            // Only find from PUBLISHED products
            const serum = products.serums.find(s => s.id === response.recommendations.serumId && s.isPublished !== false);
            if (serum) {
                dispatch({ type: 'SET_SELECTED_SERUM', payload: serum });
                selectedSerum = serum;
            }

            if(Array.isArray(response.recommendations.ampouleIds)){
                response.recommendations.ampouleIds.forEach(id => {
                    const fAmp = products.foundationAmpoules.find(a => a.id === id && a.isPublished !== false);
                    if (fAmp) {
                        dispatch({ type: 'TOGGLE_FOUNDATION_AMPOULE', payload: fAmp });
                        selectedFAmps.push(fAmp);
                    }

                    const pAmp = products.performanceAmpoules.find(a => a.id === id && a.isPublished !== false);
                    if (pAmp) {
                        dispatch({ type: 'TOGGLE_PERFORMANCE_AMPOULE', payload: pAmp });
                        selectedPAmps.push(pAmp);
                    }
                });
            }

            dispatch({ type: 'SET_MEDICAL_CHART_REPORT', payload: response.medicalChartReport });

            if (response.competitorAnalysis) {
                 dispatch({ type: 'SET_ANALYZED_USER_PRODUCTS', payload: response.competitorAnalysis });
            }

            // FIX: 初期投入時の価格計算を反映
            const cartItems = createCartFromCurrentState();
            dispatch({ type: 'SET_CART', payload: cartItems });

        } else {
            throw new Error("Invalid response format from AI");
        }

      } catch (error) {
          console.error(error);
          toast.error("診断の生成に失敗しました。");
          dispatch({ type: 'SET_VIEW', payload: 'welcome' });
      } finally {
          dispatch({ type: 'SET_MEDICAL_CHART_LOADING', payload: false });
      }
  };

  // --- Handlers for Step Wizard ---

  const handleFinishConsultation = () => {
      // Validate Basic Info
      if (!state.ageGroup || !state.skinType) {
          toast.error("年代と肌質を選択してください");
          return;
      }

      const input: ConsultationInput = {
          type: state.consultationType as any,
          ageGroup: state.ageGroup,
          skinType: state.skinType,
          knowledgeLevel: state.knowledgeLevel,
          troubleHistory: state.troubleHistory,
          // Conditionally add fields based on type
          ...(state.consultationType === 'concerns' ? {
              skinConcerns: state.skinConcerns,
              lifestyleFactors: Object.keys(state.lifestyleFactors),
              concernTimings: Object.keys(state.concernTimings)
          } : {}),
           ...(state.consultationType === 'ideal' ? {
              idealSkin: IDEAL_SKIN_GOALS.find(g => g.id === state.selectedIdealGoal)?.label || '',
              skinConcerns: state.skinConcerns,
              lifestyleFactors: Object.keys(state.lifestyleFactors),
              currentLacks: Object.keys(state.currentLacks)
          } : {}),
           ...(state.consultationType === 'investigate' ? {
              currentUserProducts: state.currentUserProducts,
              dissatisfactions: Object.keys(state.dissatisfactions),
              idealSkin: IDEAL_SKIN_GOALS.find(g => g.id === state.selectedIdealGoal)?.label || '',
              productUsageDuration: state.productUsageDuration
          } : {}),
      } as any;

      dispatch({ type: 'SET_CONSULTATION_INPUT', payload: input });
      runFullConsultationFlow(input);
  };

  // Calculate Full Plan Scores (Memoized logic moved to effect to update state)
  useEffect(() => {
      if (!state.selectedSerum) return;

      const baseScores = { ...state.selectedSerum.baseScores };

      // Calculate scores: only include ampoules if subscription
      // Note: amp.boosts are now calculated via ingredient logic in constants.ts
      if (state.purchaseType === 'subscription') {
          const allAmpoules = [...state.selectedFoundationAmpoules, ...state.selectedPerformanceAmpoules];
          allAmpoules.forEach(amp => {
              Object.entries(amp.boosts).forEach(([key, value]) => {
                  const k = key as keyof Score;
                  // Simply add the boost (concentration score) to the base score
                  baseScores[k] = Math.min(100, (baseScores[k] || 0) + (value || 0));
              });
          });
      }

      dispatch({ type: 'SET_FULL_PLAN_SCORES', payload: baseScores });
  }, [state.selectedSerum, state.selectedFoundationAmpoules, state.selectedPerformanceAmpoules, state.purchaseType]);


  const handleCameraCapture = (dataUrl: string) => {
      if (state.cameraCaptureHandler) {
          state.cameraCaptureHandler(dataUrl);
      }
      dispatch({ type: 'SET_CAMERA_OPEN', payload: false });
  };

  // --- Render Functions ---

  if (state.currentView === 'admin') {
      return <AdminDashboard onExit={() => dispatch({ type: 'SET_VIEW', payload: 'welcome' })} />;
  }

  // Unified Header matching the screenshot style (Black Logo, Simple Nav)
  const Header = () => (
    <header className="bg-white sticky top-0 z-30 w-full border-b border-stone-100">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
            {/* Logo Section */}
            <div 
                className="flex items-center gap-3 cursor-pointer group" 
                onClick={() => dispatch({ type: 'SET_VIEW', payload: 'welcome' })}
            >
                <div className="w-10 h-10 bg-stone-900 rounded-md flex items-center justify-center text-white">
                    <Cylinder size={20} className="text-white" />
                </div>
                <div className="flex flex-col">
                    <span className="font-serif font-bold text-lg tracking-wider leading-none text-stone-900">EVOLURE</span>
                    <span className="text-[10px] font-bold tracking-[0.2em] text-stone-500 leading-none mt-1">PERSONAL SKIN LAB</span>
                </div>
            </div>

            {/* Right Nav */}
            <div className="flex items-center gap-6 md:gap-8">
                <button 
                    onClick={() => dispatch({ type: 'SET_VIEW', payload: 'ingredientLab' })}
                    className="flex items-center gap-2 text-stone-500 hover:text-stone-900 font-bold text-sm transition-colors"
                >
                    <Sparkles size={16} />
                    <span className="hidden md:inline">コスメ鑑定</span>
                </button>
                <button 
                    onClick={() => {
                        dispatch({ type: 'SET_VIEW', payload: 'welcome' });
                    }}
                    className="flex items-center gap-2 text-stone-500 hover:text-stone-900 font-bold text-sm transition-colors"
                >
                    <RefreshCw size={16} />
                    <span className="hidden md:inline">はじめから</span>
                </button>
                <button 
                    onClick={() => dispatch({ type: 'TOGGLE_CART', payload: true })}
                    className="relative text-stone-900 hover:text-stone-600 transition-colors"
                >
                    <ShoppingCart size={20} />
                    {state.cart.length > 0 && (
                        <span className="absolute -top-2 -right-2 bg-stone-900 text-white text-[10px] w-4 h-4 flex items-center justify-center rounded-full font-bold border-2 border-white">
                            {state.cart.length}
                        </span>
                    )}
                </button>
            </div>
        </div>
    </header>
  );

  // Filter products for display in PlanSelectionModal
  const publishedSerums = products.serums.filter(s => s.isPublished !== false);
  const publishedFoundationAmpoules = products.foundationAmpoules.filter(a => a.isPublished !== false);
  const publishedPerformanceAmpoules = products.performanceAmpoules.filter(a => a.isPublished !== false);

  return (
    <div className="min-h-screen bg-stone-50 text-stone-900 font-sans selection:bg-stone-200">
      <Toaster position="top-center" toastOptions={{ className: 'font-sans text-sm', duration: 3000 }} />

      <CartDrawer 
        isOpen={state.isCartOpen}
        onClose={() => dispatch({ type: 'TOGGLE_CART', payload: false })}
        cart={state.cart}
        onRemoveItem={(index) => dispatch({ type: 'REMOVE_FROM_CART', payload: index })}
      />

      {/* Global Chat Modal */}
      <GlobalChatModal 
        isOpen={state.isChatOpen}
        onClose={() => dispatch({ type: 'TOGGLE_CHAT', payload: false })}
        chatHistory={state.chatHistory}
        chatInput={state.chatInput}
        onChatInputChange={(v) => dispatch({ type: 'SET_CHAT_INPUT', payload: v })}
        onSendChatMessage={handleSendChatMessage}
        isChatLoading={state.isChatLoading}
        onSuggestionClick={(q) => {
             dispatch({ type: 'SET_CHAT_INPUT', payload: q });
        }}
        currentView={state.currentView}
        selectedSerum={state.selectedSerum}
        selectedFoundationAmpoules={state.selectedFoundationAmpoules}
        selectedPerformanceAmpoules={state.selectedPerformanceAmpoules}
      />

      <ChatFAB onClick={() => {
          logEvent(currentSessionId, 'CHAT_OPEN');
          dispatch({ type: 'TOGGLE_CHAT', payload: true });
      }} />

      {state.currentView !== 'ingredientLab' && <Header />}

      {/* Main Content Area */}
      {state.currentView === 'welcome' && (
        <main className="max-w-7xl mx-auto px-6 py-20 animate-fade-in-up">
            <div className="text-center mb-24 space-y-6">
                <h1 
                    onClick={handleLogoClick}
                    className="text-6xl md:text-7xl font-serif font-medium text-stone-900 tracking-tight cursor-default select-none leading-tight"
                >
                    Science meets<br/>Personalization.
                </h1>
                <div className="space-y-2 text-stone-500 font-medium">
                    <p>AIによる多角的な肌分析で、あなただけのスキンケアレシピを。</p>
                    <p>EVOLURE Personal Skin Labへようこそ。</p>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 max-w-6xl mx-auto">
                {/* Card 1: Concerns */}
                <button 
                    onClick={() => handleStartConsultation('concerns')}
                    className="bg-white p-8 rounded-3xl border border-stone-100 shadow-lg shadow-stone-100/50 hover:shadow-xl hover:shadow-stone-200/50 hover:-translate-y-1 transition-all duration-300 text-left group flex flex-col h-full"
                >
                    <div className="w-14 h-14 bg-stone-100 rounded-2xl flex items-center justify-center mb-6 group-hover:bg-stone-900 group-hover:text-white transition-colors">
                        <User size={28} strokeWidth={1.5} />
                    </div>
                    <h3 className="text-xl font-bold text-stone-900 mb-3 font-serif">肌悩みから</h3>
                    <p className="text-sm text-stone-500 leading-relaxed mb-8 flex-grow">
                        現在の肌状態やビデオ解析から、<br/>最適なソリューションを導き出します。
                    </p>
                    <div className="flex items-center gap-2 text-xs font-bold tracking-widest text-stone-900 uppercase mt-auto group-hover:gap-3 transition-all">
                        START <ArrowRight size={14} />
                    </div>
                </button>

                {/* Card 2: Ideal */}
                <button 
                    onClick={() => handleStartConsultation('ideal')}
                    className="bg-white p-8 rounded-3xl border border-stone-100 shadow-lg shadow-stone-100/50 hover:shadow-xl hover:shadow-stone-200/50 hover:-translate-y-1 transition-all duration-300 text-left group flex flex-col h-full"
                >
                    <div className="w-14 h-14 bg-stone-100 rounded-2xl flex items-center justify-center mb-6 group-hover:bg-stone-900 group-hover:text-white transition-colors">
                        <Target size={28} strokeWidth={1.5} />
                    </div>
                    <h3 className="text-xl font-bold text-stone-900 mb-3 font-serif">理想の肌から</h3>
                    <p className="text-sm text-stone-500 leading-relaxed mb-8 flex-grow">
                        なりたい肌のイメージとライフスタイルから、未来を見据えたプランを設計します。
                    </p>
                    <div className="flex items-center gap-2 text-xs font-bold tracking-widest text-stone-900 uppercase mt-auto group-hover:gap-3 transition-all">
                        START <ArrowRight size={14} />
                    </div>
                </button>

                {/* Card 3: Products */}
                <button 
                    onClick={() => handleStartConsultation('investigate')}
                    className="bg-white p-8 rounded-3xl border border-stone-100 shadow-lg shadow-stone-100/50 hover:shadow-xl hover:shadow-stone-200/50 hover:-translate-y-1 transition-all duration-300 text-left group flex flex-col h-full"
                >
                    <div className="w-14 h-14 bg-stone-100 rounded-2xl flex items-center justify-center mb-6 group-hover:bg-stone-900 group-hover:text-white transition-colors">
                        <Search size={28} strokeWidth={1.5} />
                    </div>
                    <h3 className="text-xl font-bold text-stone-900 mb-3 font-serif">現在の製品から</h3>
                    <p className="text-sm text-stone-500 leading-relaxed mb-8 flex-grow">
                        使用中の製品と比較し、足りない要素を補完するアップグレードプランを提案します。
                    </p>
                    <div className="flex items-center gap-2 text-xs font-bold tracking-widest text-stone-900 uppercase mt-auto group-hover:gap-3 transition-all">
                        START <ArrowRight size={14} />
                    </div>
                </button>
            </div>
        </main>
      )}

      {state.currentView === 'ingredientLab' && (
          <div className="min-h-screen bg-stone-50">
              <header className="bg-white border-b border-stone-200 sticky top-0 z-30">
                  <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
                      <div className="flex items-center gap-2 cursor-pointer" onClick={() => dispatch({ type: 'SET_VIEW', payload: 'welcome' })}>
                          <div className="w-8 h-8 bg-stone-900 rounded-lg flex items-center justify-center text-white font-serif font-bold">E</div>
                          <span className="font-serif font-bold text-xl tracking-tight">EVOLURE</span>
                      </div>
                      <button onClick={() => dispatch({ type: 'SET_VIEW', payload: 'welcome' })} className="p-2 text-stone-400 hover:text-stone-900"><X /></button>
                  </div>
              </header>
              <IngredientLab 
                  setIsCameraOpen={(open) => dispatch({ type: 'SET_CAMERA_OPEN', payload: open })}
                  setCameraCaptureHandler={(handler) => dispatch({ type: 'SET_CAMERA_HANDLER', payload: handler })}
              />
          </div>
      )}

      {state.currentView === 'consultation' && (
         <div className="min-h-screen bg-stone-50 flex flex-col">
            <div className="text-center pt-12 pb-8 bg-stone-50">
                <h1 className="text-3xl font-serif font-bold text-stone-900 mb-2">AI Consultation</h1>
                <p className="text-stone-500 text-sm">現在の肌状態について教えてください</p>
            </div>

            <main className="flex-grow max-w-3xl mx-auto w-full p-6 md:p-12 pb-32">
                <div className="space-y-12">
                    {/* Section 1: Basic Info */}
                    <ConsultationStep step={1} title="基本情報">
                        <div className="space-y-8">
                             <div>
                                <label className="block text-sm font-bold text-stone-600 mb-3">年代</label>
                                <div className="grid grid-cols-3 gap-3">
                                    {AGE_GROUPS.map(age => (
                                        <button
                                            key={age}
                                            onClick={() => dispatch({ type: 'SET_AGE_GROUP', payload: age })}
                                            className={`p-4 rounded-lg border text-sm font-medium transition-all duration-200 ${state.ageGroup === age ? 'bg-stone-900 text-white border-stone-900 shadow-md' : 'bg-white text-stone-600 border-stone-200 hover:border-stone-400'}`}
                                        >
                                            {age}
                                        </button>
                                    ))}
                                </div>
