const buildUserProfileString = (input: ConsultationInput): string => {
    const userInfoParts: string[] = [
        `- **アプローチタイプ:** ${input.type}`,
        `- **年代:** ${input.ageGroup}`,
        `- **肌質:** ${input.skinType}`,
        `- **化粧品知識レベル:** ${input.knowledgeLevel}/5`,
        `- **肌トラブルの経験:** ${input.troubleHistory || '特になし'}`,
        `- **好みの成分:** ${input.preferredIngredients?.join(', ') || '特になし'}`,
        `- **避けたい成分:** ${input.avoidedIngredients?.join(', ') || '特になし'}`
    ];

    if (input.type === 'concerns') {
        const concernsString = Object.entries(input.skinConcerns).map(([c, s]) => `${c} (${s}/5)`).join(', ');
        userInfoParts.push(`- **主な肌悩み:** ${concernsString}`);
        userInfoParts.push(`- **気になる生活習慣:** ${input.lifestyleFactors.join(', ')}`);
        userInfoParts.push(`- **悩みのタイミング:** ${input.concernTimings.join(', ')}`);
    } else if (input.type === 'ideal') {
        userInfoParts.push(`- **なりたい肌:** ${input.idealSkin}`);
        userInfoParts.push(`- **現在の不足感:** ${input.currentLacks.join(', ')}`);
    } else if (input.type === 'investigate') {
        userInfoParts.push(`- **現在使用中:** ${input.currentUserProducts.join('、')}`);
        userInfoParts.push(`- **不満点:** ${input.dissatisfactions.join(', ')}`);
    }
    return userInfoParts.join('\n');
};

export const runFullConsultation = async (
    input: ConsultationInput
): Promise<FullConsultationResponse> => {
    const userProfileString = buildUserProfileString(input);
    const benchmarkDataString = BENCHMARK_COMPETITORS.map(p => `- ${p.name}: ${SCORE_CATEGORY_KEYS.map(k => `${k} ${p.scores[k]}`).join(', ')}`).join('\n');

