2. ユーザーが「避けたい成分」を指定している場合、処方意図の中でその成分が含まれていないこと、または配慮されていることを説明してください。

${userProfileString}

EVOLUREカタログ: ${JSON.stringify(ALL_PRODUCTS, null, 2)}
成分辞書: ${JSON.stringify(INGREDIENT_DESCRIPTIONS, null, 2)}
ベンチマーク: ${benchmarkDataString}

薬機法を遵守し、知識レベル${input.knowledgeLevel}に合わせた専門的なレポートをJSON形式で出力してください。
`;
    const isInvestigate = input.type === 'investigate';
    const modelConfig: GenerateContentParameters['config'] = {};
    if (isInvestigate) modelConfig.tools = [{ googleSearch: {} }];
    else {
        modelConfig.responseMimeType = "application/json";
        modelConfig.responseSchema = fullConsultationSchema;
    }

    const response = await callGeminiWithRetry(
        () => ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: prompt,
            config: modelConfig,
        }),
        "AIによる分析とプラン生成に失敗しました。",
        "AIサーバーが混み合っています。しばらくしてからもう一度お試しください。"
    );

    let parsedData = isInvestigate ? extractJson(response.text) : JSON.parse(response.text);
    const citations = response.candidates?.[0]?.groundingMetadata?.groundingChunks
        ?.map(chunk => ({ uri: chunk.web?.uri || '', title: chunk.web?.title || '引用元情報' }))
        .filter(c => c.uri) ?? [];

    const result: FullConsultationResponse = { ...parsedData, citations };
    if (result.competitorAnalysis) {
        result.competitorAnalysis = result.competitorAnalysis.map(p => ({
            ...p,
            name: `現在: ${p.productName || p.name}`,
            citations: result.citations
        }));
