export const sendChatMessageStream = async (chatSession: Chat | null, message: string): Promise<AsyncIterable<GenerateContentResponse>> => {
  if (!chatSession) {
    async function* errorStream(): AsyncGenerator<GenerateContentResponse> {
        yield { text: "エラー: チャットセッションがありません。" } as GenerateContentResponse;
    }
    return errorStream();
  }

  try {
    return await chatSession.sendMessageStream({ message });
  } catch (error) {
    async function* errorStream(): AsyncGenerator<GenerateContentResponse> {
        yield { text: "申し訳ありません。メッセージの送信中にエラーが発生しました。" } as GenerateContentResponse;
    }
    return errorStream();
  }
};

export const analyzeCompetitorProduct = async (
    productNames: string[], 
    skinConcerns: string[], 
    evolurePlan?: { name: string; scores: Score }
): Promise<AnalyzedCompetitor[] | null> => {

    const evolurePlanString = evolurePlan
        ? `比較対象のEVOLUREプラン: ${evolurePlan.name} (各項目のスコア: ${SCORE_CATEGORY_KEYS.map(key => `${String(key)}: ${evolurePlan.scores[key]}`).join(', ')})`
        : '比較対象のEVOLUREプランはありません。製品単体で分析してください。';

    const productNamesString = productNames.map(name => `- 「${name}」`).join('\n');

    const benchmarkDataString = BENCHMARK_COMPETITORS.map(p => 
        `- ${p.name} (${p.priceTier}): ${SCORE_CATEGORY_KEYS.map(key => `${String(key)} ${p.scores[key]}`).join(', ')}`
    ).join('\n');

    const prompt = `
あなたは公平で専門的なスキンケア製品アナリストです。

**分析対象製品リスト:**
${productNamesString}

**ユーザー情報:**
- 主な肌悩み: ${skinConcerns.join('、')}
- ${evolurePlanString}

**あなたのタスク:**
リストにある**各製品ごと**に、ウェブ上の公開情報（公式HP、レビューサイト、SNSの口コミ、成分情報など）を検索・分析し、以下の情報を生成してください。
検索結果が具体的でない場合でも、**製品の価格帯、ブランドイメージ、カテゴリ（美容液、導入液など）から専門知識を用いて必ずスコアを推定してください。**
**「情報が見つかりません」という回答は禁止です。**

出力は**単一のJSONオブジェクト**とし、必ず \`\`\`json ... \`\`\` で囲んでください。
そのJSONオブジェクトは、"analysis"というキーを持つ必要があり、その値は各製品の分析結果オブジェクトの配列です。

---
### 【スコアリングの絶対的ルール】
- **全カテゴリ必須:** \`scores\`オブジェクトには、以下の5つのキーが**必ず**含まれてなければなりません。キーを省略することは許可されません。
- **スコア範囲 (50-100):** 各カテゴリのスコアは、**必ず50から100の整数**にしてください。
- **【最重要】合理的推定:** 特定の製品の詳細なラボデータが見つからない場合でも、**絶対にエラーを返さないでください。** 代わりに、製品の成分、価格、謳い文句、ブランドの特性から専門家として**妥当なスコアを推定**してください。
- **ベンチマークの参照:** スコアリングの際、以下のベンチマーク製品リストを**絶対的な基準**として使用してください。
  **ベンチマークリスト:**
  ${benchmarkDataString}

---
### 【レポート作成の重要ルール】
1.  **productName (string):** 分析した製品の名前。
2.  **scores (object):** 上記のルールに厳密に従ってスコアリングした結果。
3.  **report (string):** Markdown形式の詳細分析レポート。**レポート本文には引用番号（例: [1]）を含めないでください。**
4.  **【最重要】JSONフォーマットの厳守:**
    - **引用符の扱い:** 文字列の値の中で引用符（ダブルクオーテーション "）を使用することは **絶対に禁止** します。代わりに日本語の鉤括弧「」を使用してください。

**JSON出力形式の例:**
\`\`\`json
{
  "analysis": [
    {
      "productName": "製品名A",
      "scores": {
        "シミ・くすみ": 85,
        "シワ・小ジワ": 85,
        "ハリ・弾力": 85,
        "毛穴ケア": 85,
        "保湿持続性": 85
      },
      "report": "製品Aは、特に保湿力に優れた製品として評価されています。..."
    }
  ]
}
\`\`\`
`;

    try {
        const response = await callGeminiWithRetry(
            () => ai.models.generateContent({
                model: "gemini-3-flash-preview",
                contents: prompt,
                config: {
                    tools: [{ googleSearch: {} }],
                },
            }),
            "AIによる競合製品の分析中に予期せぬエラーが発生しました。",
            "AIサーバーが混み合っています。しばらくしてからもう一度お試しください。"
        );

        const parsedData = extractJson(response.text);

        const citations = response.candidates?.[0]?.groundingMetadata?.groundingChunks
            ?.map(chunk => ({
                uri: chunk.web?.uri || '',
                title: chunk.web?.title || '引用元情報'
            }))
            .filter(c => c.uri) ?? [];

        if (parsedData.analysis && Array.isArray(parsedData.analysis)) {
            return parsedData.analysis.map((item: any): AnalyzedCompetitor => {
                const validatedScores: Partial<Score> = {};
                SCORE_CATEGORY_KEYS.forEach(key => {
                    const score = item.scores?.[key];
                    if (typeof score === 'number' && score >= 50 && score <= 100) {
                        validatedScores[key] = score;
                    } else {
                        validatedScores[key] = 60;
                    }
                });

                return {
                    name: item.productName || '名称不明の製品',
                    scores: validatedScores as Score,
                    report: item.report || 'レポートがありません。',
                    citations: citations
                };
            });
        }
        return null;
    } catch (error) {
        console.error("Failed to get competitor analysis from Gemini:", error);
        return null;
    }
};

