プラン: ${productsString}
カタログ: ${JSON.stringify(ALL_PRODUCTS, null, 2)}
成分辞書: ${JSON.stringify(INGREDIENT_DESCRIPTIONS, null, 2)}
`;

    const response = await callGeminiWithRetry(
        () => ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: prompt,
